<script setup lang="ts">
import { onMounted, onUnmounted, ref } from 'vue'; import { PhPulse, PhProhibit, PhArrowClockwise } from '@phosphor-icons/vue'; import { BrpApi,type JobRecord } from '../api'; import { useAppStore } from '../stores/app'
const store=useAppStore();const api=new BrpApi(store.apiBaseUrl);const jobs=ref<JobRecord[]>([]);const error=ref('');let timer:number|undefined
async function load(){try{jobs.value=await api.jobs(store.siteId)}catch(cause){error.value=cause instanceof Error?cause.message:'Jobs unavailable'}} async function cancel(job:JobRecord){await api.cancelJob(store.siteId,job.id,store.actor);await load()}
onMounted(()=>{void load();timer=window.setInterval(load,3000)});onUnmounted(()=>clearInterval(timer))
</script>
<template><section><header class="page-header"><div><p class="page-kicker">Runtime control</p><h1>Operations</h1><p>Durable jobs, retries, correlation IDs and worker progress.</p></div><button class="secondary-button" @click="load"><PhArrowClockwise :size="15" />Refresh</button></header><div v-if="error" class="inline-alert">{{ error }}</div><section class="surface table-surface"><div v-if="!jobs.length" class="empty-state"><PhPulse :size="32"/><strong>No jobs for this site</strong></div><table v-else><thead><tr><th>Job</th><th>Status</th><th>Progress</th><th>Attempts</th><th>Correlation ID</th><th>Submitted</th><th></th></tr></thead><tbody><tr v-for="job in jobs" :key="job.id"><td><strong>{{ job.type.replaceAll('_',' ') }}</strong><small>{{ job.createdBy }}</small></td><td><span class="status-badge">{{ job.status }}</span></td><td><div class="progress-cell"><progress :value="job.progress" max="100"></progress><span>{{ job.progress }}%</span></div></td><td>{{ job.attempts }} / {{ job.maxAttempts }}</td><td><code>{{ job.correlationId.slice(0,12) }}</code></td><td>{{ new Date(job.createdAt).toLocaleString() }}</td><td><button v-if="['QUEUED','RUNNING'].includes(job.status)" class="icon-button" aria-label="Cancel job" @click="cancel(job)"><PhProhibit :size="15" /></button></td></tr></tbody></table></section></section></template>
